<?php use App\Helpers\Csrf; use App\Helpers\Sanitizer; use App\Helpers\Url; $rol=$rol??[]; $permisos=$permisos??[]; $permisosSeleccionados=array_map('intval',$permisosSeleccionados??[]); $errores=$errores??[]; $modo=$modo??'crear'; $action=$action??'/roles/guardar'; $grupos=[]; foreach($permisos as $permiso){ $grupos[$permiso['modulo'] ?? 'General'][]=$permiso; } ?>
<?php if($errores!==[]): ?><div class="alerta alerta--error"><ul><?php foreach($errores as $error): ?><li><?= Sanitizer::html($error) ?></li><?php endforeach; ?></ul></div><?php endif; ?>
<form class="card form-wide" method="POST" action="<?= Sanitizer::html(Url::ruta($action)) ?>"><?= Csrf::campo() ?><div class="form-grid"><div class="form-group"><label>Nombre del rol</label><input name="nombre" required value="<?= Sanitizer::html($rol['nombre'] ?? '') ?>"></div><div class="form-group"><label>Descripción</label><input name="descripcion" value="<?= Sanitizer::html($rol['descripcion'] ?? '') ?>"></div></div><label class="check-line"><input type="checkbox" name="activo" value="1" <?= (int)($rol['activo'] ?? 1)===1?'checked':'' ?>> Rol activo</label><section class="inner-panel"><h2>Permisos</h2><p class="muted">Selecciona las acciones que puede realizar este rol.</p><?php foreach($grupos as $grupo=>$items): ?><h3><?= Sanitizer::html($grupo) ?></h3><div class="checkbox-grid"><?php foreach($items as $permiso): ?><label class="option-card"><input type="checkbox" name="permisos[]" value="<?= (int)$permiso['id'] ?>" <?= in_array((int)$permiso['id'],$permisosSeleccionados,true)?'checked':'' ?>><span><strong><?= Sanitizer::html($permiso['clave']) ?></strong><small><?= Sanitizer::html($permiso['descripcion'] ?? '') ?></small></span></label><?php endforeach; ?></div><?php endforeach; ?></section><div class="form-actions"><a class="btn btn-secundario" href="<?= Sanitizer::html(Url::ruta('/roles')) ?>">Cancelar</a><button class="btn" type="submit"><?= $modo==='crear'?'Guardar rol':'Actualizar rol' ?></button></div></form>
